mapper.select:
SELECT /* @SQLID=SUB020302_0104-01#Sql001 */ * FROM ( SELECT COUNT(*) OVER() AS totalRow ,VP.BROKER_CODE AS brokerCode ,VP.BROKER_CHARGE_CODE AS empCode ,VP.BROKER_CHARGE_NAME AS brokerChargeName ,VP.BUTEN_CODE AS buten ,VP.ACCOUNT_NUMBER AS accountNumber ,VP.DEALER_NUMBER AS dealerNumber ,VP.CUSTOMER_ATTRIBUTE_NAME AS courceName ,VP.CUSTOMER_ATTRIBUTE AS customerAttribute ,VP.PRODUT_NAME AS securiytClassName ,VP.BRAND_CODE AS brandCode ,VP.BRAND_NAME AS brandName ,VP.EXEC_BASE_BALANCE AS contractStandardDeposit ,VP.CURRENCY AS currency ,VP.PAYMENT_NAME AS paymentClass ,VP.PAYMENT_TYPE AS paymentType ,TO_CHAR(TO_DATE(VP.SCHEDULE_DATE,'YYYY/MM/DD'),'YYYY/MM/DD') AS scheduleDate ,VP.NEXT_INTEREST AS nextInterest ,VP.SCHEDULE_PRICE AS schedulePrice ,VP.BROKER_BRANCH_CODE AS branchCode ,MB2.BRANCH_NAME AS branchName ,MUAI.NAME_KANJI AS customerNameKanji ,MUAI.NAME_KANA AS customerNameKana ,MB.BRANCH_NAME AS brokerName ,SBEP.SBEP_EARLY_PAYMENT_JUDGE_DATE AS couponDeterminationDate ,NVL(SBJM.KI_COUNT,0) AS kiCount FROM V_PAYMENT VP INNER JOIN MEDIATE_USER_ATTRIBUTE_INFO MUAI ON VP.BUTEN_CODE = MUAI.BUTEN_CODE AND VP.ACCOUNT_NUMBER = MUAI.ACCOUNT_NUMBER AND VP.BROKER_CODE = MUAI.BROKER_CODE LEFT OUTER JOIN MEDIATE_BRANCH MB ON VP.BROKER_CODE = MB.BROKER_CODE AND MB.BROKER_BRANCH_KIND = '00' AND MB.DELETE_FLG = '0' LEFT OUTER JOIN MEDIATE_BRANCH MB2 ON VP.BROKER_CODE = MB2.BROKER_CODE AND VP.BROKER_BRANCH_CODE = MB2.BROKER_BRANCH_CODE AND MB2.DELETE_FLG = '0' LEFT OUTER JOIN ( SELECT SBEP.SBEP_BOND_CODE ,SCHEDULE_DATE ,MAX(SBEP.SBEP_EARLY_PAYMENT_JUDGE_DATE) AS SBEP_EARLY_PAYMENT_JUDGE_DATE FROM STRUCTURED_BOND_EARLY_PAY SBEP LEFT OUTER JOIN ( SELECT DISTINCT BRAND_CODE ,SCHEDULE_DATE FROM V_PAYMENT ) VP ON VP.BRAND_CODE = SBEP.SBEP_BOND_CODE WHERE VP.SCHEDULE_DATE > SBEP.SBEP_EARLY_PAYMENT_JUDGE_DATE GROUP BY SBEP.SBEP_BOND_CODE, SCHEDULE_DATE ) SBEP ON VP.BRAND_CODE = SBEP.SBEP_BOND_CODE AND VP.SCHEDULE_DATE = SBEP.SCHEDULE_DATE LEFT OUTER JOIN ( SELECT SBJM_BOND_CODE ,SUM(CASE WHEN SBJM_NOCKIN_ONSET_DATE IS NOT NULL THEN 1 ELSE 0 END) AS KI_COUNT FROM STRUCTURED_BOND_JUDGE_MST GROUP BY SBJM_BOND_CODE ) SBJM ON VP.BRAND_CODE = SBJM.SBJM_BOND_CODE WHERE 1=1
AND VP.BUTEN_CODE = #{req.butenCode}
AND VP.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND TO_DATE(VP.SCHEDULE_DATE,'yyyymmdd') >= TO_DATE(#{req.periodYmFrom},'yyyy/mm/dd')
AND TO_DATE(VP.SCHEDULE_DATE,'yyyymmdd') <= TO_DATE(#{req.periodYmTo},'yyyy/mm/dd')
AND VP.PRODUT_CD IN
#{item}
AND LPAD(VP.BRAND_CODE,12,'0') = LPAD(#{req.brandCode},12,'0')
AND VP.BROKER_CODE NOT IN
AND VP.BROKER_CODE IN
#{item}
AND VP.BROKER_CHARGE_CODE = #{req.empCode}
AND 1 = 1
AND (
(VP.BROKER_CODE = #{item.brokerCode})
)
AND (
(VP.BROKER_CODE = #{item.brokerCode} AND VP.BROKER_CHARGE_CODE = #{item.empCode})
)
AND VP.BROKER_BRANCH_CODE = #{req.branchCode}
AND ( MUAI.NAME_KANJI = #{req.customerNameKanjiKana} OR MUAI.NAME_KANA = #{req.customerNameKanjiKana} )
AND ( MUAI.NAME_KANJI LIKE #{req.customerNameKanjiKana} || '% OR MUAI.NAME_KANA LIKE #{req.customerNameKanjiKana} || '%' )
AND ( MUAI.NAME_KANJI LIKE '%' || #{req.customerNameKanjiKana} || '%' OR MUAI.NAME_KANA LIKE '%' || #{req.customerNameKanjiKana} || '%' )
AND VP.CUSTOMER_ATTRIBUTE IN
#{item.id}
ORDER BY VP.SCHEDULE_DATE DESC, VP.BROKER_CODE ASC, VP.BUTEN_CODE ASC, VP.ACCOUNT_NUMBER ASC
ORDER BY VP.SCHEDULE_DATE DESC, VP.BUTEN_CODE ASC, VP.ACCOUNT_NUMBER ASC
) WHERE ROWNUM <= #{req.rownum}
